package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds. It uses the system 'ping' command via
// os/exec and parses the output to extract the average RTT. The function works
// on both Unix‑like systems (Linux, macOS) and Windows.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Determine the flag for the number of packets based on the OS.
	pingCountFlag := "-c"
	if runtime.GOOS == "windows" {
		pingCountFlag = "-n"
	}

	// Build the command directly, avoiding shell invocation to prevent
	// issues with quoting and to improve portability.
	cmd := exec.Command("ping", pingCountFlag, strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	outStr := string(output)

	// Choose the parsing strategy depending on the platform.
	if runtime.GOOS == "windows" {
		return parseWindowsPing(outStr)
	}
	return parseUnixPing(outStr)
}

// parseUnixPing extracts the average RTT from the output of ping on Unix‑like
// systems (Linux, macOS). It looks for a line containing "min/avg/max".
func parseUnixPing(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "min/avg/max") {
			statsLine = line
			break
		}
	}
	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// The line typically looks like:
	//   rtt min/avg/max/mdev = 1.234/2.345/3.456/0.789 ms
	//   round-trip min/avg/max = 1.234/2.345/3.456 ms
	// The regex below captures the average value (the second number).
	re := regexp.MustCompile(`[\d.]+/([\d.]+)(?:/\d+\.\d+)?\s+ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avg, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}
	return avg, nil
}

// parseWindowsPing extracts the average RTT from the output of ping on Windows.
// It searches for a line containing "Average =".
func parseWindowsPing(output string) (float64, error) {
	re := regexp.MustCompile(`(?i)Average\s*=\s*([\d.]+)\s*ms`)
	matches := re.FindStringSubmatch(output)
	if len(matches) < 2 {
		return 0, errors.New("could not find average latency in Windows ping output")
	}

	avg, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}
	return avg, nil
}

func main() {
	// Example: measure latency to Google DNS (8.8.8.8) with 5 pings.
	host := "8.8.8.8"
	count := 5

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency to %s (%d pings): %.2f ms\n", host, count, latency)
}

