package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
	"unicode"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds. It uses the system 'ping' command via
// os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	// Basic validation
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Prevent the host from being interpreted as a flag (e.g., "-n").
	if strings.HasPrefix(host, "-") {
		return 0, errors.New("host must not start with '-'")
	}

	// Use exec.Command with separate arguments to avoid shell injection.
	// The -c flag expects a numeric count.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	avg, err := parsePingOutput(string(output))
	if err != nil {
		return 0, err
	}

	return avg, nil
}

// parsePingOutput extracts the average round‑trip time from the ping command output.
// It supports the typical Linux format:
//   rtt min/avg/max/mdev = X.XXX/Y.YYY/Z.ZZZ ms
// and the macOS/BSD format:
//   round-trip min/avg/max = X.XXX/Y.YYY/Z.ZZZ ms
func parsePingOutput(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	for _, line := range lines {
		// Look for a line that contains "ms" and an "=" sign.
		if !strings.Contains(line, "ms") || !strings.Contains(line, "=") {
			continue
		}
		// Split on "=" to isolate the numeric part.
		parts := strings.SplitN(line, "=", 2)
		if len(parts) < 2 {
			continue
		}
		// The right side contains something like "1.234/2.345/3.456 ms"
		// or "1.234/2.345/3.456/0.123 ms". Remove the trailing "ms".
		right := strings.TrimSpace(parts[1])
		right = strings.TrimRightFunc(right, func(r rune) bool {
			return unicode.IsLetter(r) || r == ' '
		})
		// Split on '/' to get the numbers.
		numbers := strings.Split(right, "/")
		if len(numbers) < 2 {
			continue
		}
		// The average is the second token (index 1).
		avgStr := strings.TrimSpace(numbers[1])
		avg, err := strconv.ParseFloat(avgStr, 64)
		if err != nil {
			continue
		}
		return avg, nil
	}
	return 0, errors.New("could not find average latency in ping output")
}

// main demonstrates a simple usage of MeasureLatency.
func main() {
	// For demonstration purposes we hardcode the host and count.
	// In a real application these could be read from command‑line flags or environment variables.
	host := "example.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency to %s: %.2f ms\n", host, avg)
}

