// and returns the average round‑trip time in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("count must be greater than 0")
	}

	// Execute the ping command.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	out, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	// Try to find the line that contains the summary statistics:
	// e.g. "round-trip min/avg/max/stddev = 1.2/2.3/4.5/0.6 ms"
	scanner := bufio.NewScanner(strings.NewReader(string(out)))
	var summaryLine string
	for scanner.Scan() {
		line := scanner.Text()
		if strings.Contains(line, "round-trip") {
			summaryLine = line
			break
		}
	}
	if err := scanner.Err(); err != nil {
		return 0, fmt.Errorf("scanning ping output: %w", err)
	}

	// If we have the summary line, extract the average value.
	if summaryLine != "" {
		parts := strings.Split(summaryLine, "=")
		if len(parts) < 2 {
			return 0, errors.New("unexpected format of round-trip line")
		}
		stats := strings.Split(strings.TrimSpace(parts[1]), "/")
		if len(stats) < 2 {
			return 0, errors.New("unexpected stats format")
		}
		avgStr := strings.TrimSpace(stats[1])
		// Remove possible trailing "ms".
		avgStr = strings.TrimRight(avgStr, "ms")
		avgStr = strings.TrimSpace(avgStr)

		avg, err := strconv.ParseFloat(avgStr, 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency %q: %w", avgStr, err)
		}
		return avg, nil
	}

	// Fallback: parse each "time=..." line and compute the average manually.
	var total float64
	var cnt int
	scanner2 := bufio.NewScanner(strings.NewReader(string(out)))
	for scanner2.Scan() {
		line := scanner2.Text()
		idx := strings.Index(line, "time=")
		if idx == -1 {
			continue
		}
		rest := line[idx+5:]
		// Find the end of the numeric value (stop at first non‑digit).
		end := strings.IndexFunc(rest, func(r rune) bool {
			return r < '0' || r > '9'
		})
		if end == -1 {
