		}
		numStr := strings.TrimSpace(rest[:end])
		val, err := strconv.ParseFloat(numStr, 64)
		if err != nil {
			continue
		}
		total += val
		cnt++
	}
	if cnt == 0 {
		return 0, errors.New("could not parse latency from ping output")
	}
	return total / float64(cnt), nil
}

func main() {
