package main

import (
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the given host the specified number of times
// and returns the average round‑trip time in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be > 0, got %d", count)
	}

	var cmd *exec.Cmd
	// Use -c for Unix‑like systems, -n for Windows.
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping failed: %w", err)
	}

	// Regex to capture "time=XX.X ms" (Linux/macOS) or "time=XXms" (Windows).
	// It also matches "time<1 ms" where the numeric part may be absent.
	re := regexp.MustCompile(`time[=<]?(\d+(?:\.\d+)?)\s*ms`)
	matches := re.FindAllStringSubmatch(string(output), -1)

	if len(matches) == 0 {
		return 0, fmt.Errorf("no latency information found in ping output")
	}

	var total float64
	for _, match := range matches {
		if len(match) < 2 {
			continue
		}
		val, err := strconv.ParseFloat(match[1], 64)
		if err != nil {
			// Ignore malformed numbers.
			continue
		}
		total += val
	}

	if total == 0 && len(matches) == 0 {
		return 0, fmt.Errorf("could not parse any latency values")
	}

	return total / float64(len(matches)), nil
}

func main() {
	// Simple CLI: first argument is host, second is number of pings.
	// Example: ./latency google.com 4
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Invalid count: %v\n", err)
		os.Exit(1)
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avg)
}

