)

// MeasureLatency pings the given host with count times and returns average round‑trip time in milliseconds.
// It returns an error if host is empty, count <= 0, ping fails, or output cannot be parsed.
func MeasureLatency(host string, count int) (float64, error) {
	if strings.TrimSpace(host) == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Use a context with a timeout to avoid hanging forever.
	// Each ping will wait at most 2 seconds (-W 2) plus some margin.
	ctx, cancel := context.WithTimeout(context.Background(), time.Duration(count)*2*time.Second+5*time.Second)
	defer cancel()

	// Build the ping command directly without a shell to prevent injection.
	// -c <count>  Number of packets to send.
	// -W <sec>   Timeout for each reply (Linux). macOS/BSD ignore this flag.
	cmd := exec.CommandContext(ctx, "ping", "-c", strconv.Itoa(count), "-W", "2", host)

	output, err := cmd.CombinedOutput()
	if err != nil {
		// If the context timed out, give a clearer error.
		if ctx.Err() == context.DeadlineExceeded {
			return 0, fmt.Errorf("ping timed out after %v seconds", time.Duration(count)*2+5)
		}
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Look for the line containing the RTT statistics.
	// Two common formats:
	//   Linux:    "rtt min/avg/max/mdev = X.Y/Z.W/V.U/W.X ms"
	//   macOS/BSD:"round‑trip min/avg/max = X.Y/Z.W/V.U ms"
	var avgStr string
	for _, line := range strings.Split(string(output), "\n") {
		// Try Linux format.
		if m := regexp.MustCompile(`rtt min/avg/max/mdev\s*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+`).FindStringSubmatch(line); len(m) >= 2 {
			avgStr = m[1]
			break
		}
		// Try macOS/BSD format.
		if m := regexp.MustCompile(`round‑trip min/avg/max\s*=\s*[\d.]+/([\d.]+)/[\d.]+`).FindStringSubmatch(line); len(m) >= 2 {
			avgStr = m[1]
			break
		}
	}

	if avgStr == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency: %w", err)
	}

	return avg, nil
}

func main() {
	// Minimal CLI: latency <host> [count]
	if len(os.Args) < 2 {
		fmt.Fprintf(os.Stderr, "Usage: %s <host> [count]\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count := 4 // default
	if len(os.Args) >= 3 {
		c, err := strconv.Atoi(os.Args[2])
		if err != nil {
			fmt.Fprintf(os.Stderr, "Invalid count: %v\n", err)
			os.Exit(1)
		}
		count = c
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency to %s: %.2f ms\n", host, avg)
}

