	// A reasonable timeout: count * 5 seconds plus a small buffer.
	timeout := time.Duration(count*5+10) * time.Second
	ctx, cancel := context.WithTimeout(context.Background(), timeout)
	defer cancel()

	if runtime.GOOS == "windows" {
		cmd = exec.CommandContext(ctx, "ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.CommandContext(ctx, "ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		// If ping fails we still try to extract a result from the output.
		// However, for simplicity we return the error.
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	outStr := string(output)

	// The summary line on Linux/macOS looks like:
	//   rtt min/avg/max/stddev = 1.234/2.345/3.456/0.123 ms
	// On macOS it can be "round-trip min/avg/max/stddev".
	// We try a specific pattern first.
	re := regexp.MustCompile(`(?i)(?:rtt|round-trip)\s+min/avg/max/(?:stddev)?\s*=\s*[\d\.]+/([\d\.]+)/[\d\.]+`)
	matches := re.FindStringSubmatch(outStr)
	if len(matches) >= 2 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency: %w", err)
		}
		return avg, nil
	}

	// Fallback: look for any "x/y/z" pattern and take the middle value.
	re2 := regexp.MustCompile(`(\d+\.\d+)/(\d+\.\d+)/(\d+\.\d+)`)
	all := re2.FindAllStringSubmatch(outStr, -1)
	if len(all) == 0 {
		return 0, fmt.Errorf("could not parse ping output")
	}
	// The last occurrence is the summary line.
	last := all[len(all)-1]
	avg, err := strconv.ParseFloat(last[2], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency: %w", err)
	}
	return avg, nil
}

func main() {
	host := flag.String("host", "google.com", "Host to ping")
	count := flag.Int("count", 4, "Number of ping attempts")
	flag.Parse()

	avgLatency, err := MeasureLatency(*host, *count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency to %s: %.2f ms\n", *host, avgLatency)
}

