// MeasureLatency pings the given host `count` times and returns the average
// latency in milliseconds. It uses the system `ping` command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host is empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be greater than zero")
	}

	// Build the ping command. Using -c to limit the number of packets.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping failed: %w", err)
	}

	// Parse each line of the output looking for "time=X" (in ms).
	// The format is either "time=0.123 ms" or "time=0.123".
	re := regexp.MustCompile(`time[=<](\d+\.?\d*)`)
	var total float64
	var hits int

	scanner := bufio.NewScanner(strings.NewReader(string(output)))
	for scanner.Scan() {
		line := scanner.Text()
		matches := re.FindStringSubmatch(line)
		if len(matches) < 2 {
			continue
		}
		// matches[1] holds the numeric part.
		val, err := strconv.ParseFloat(matches[1], 64)
		if err != nil {
			// If we cannot parse, just skip.
			continue
		}
		total += val
		hits++
	}

	if err := scanner.Err(); err != nil {
		return 0, fmt.Errorf("error reading ping output: %w", err)
	}

	if hits == 0 {
		return 0, errors.New("no latency values could be parsed from ping output")
	}

	average := total / float64(hits)
	return average, nil
}

func main() {
	// Simple CLI: expects two arguments: <host> <count>
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Invalid count: %v\n", err)
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

