package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times
// and returns the average round‑trip time in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Run the ping command with the requested count.
	// Using exec.Command directly avoids shell quoting issues.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Locate the line that contains the RTT statistics.
	// The line typically looks like:
	//   rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	//   round‑trip min/avg/max/stddev = 12.345/23.456/34.567 ms
	var statsLine string
	for _, line := range strings.Split(string(output), "\n") {
		if strings.Contains(line, "min/avg") && strings.Contains(line, "=") {
			statsLine = line
			break
		}
	}
	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract the three (or more) latency values after the "=".
	// The second number is the average.
