package main

import (
	"bufio"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the given host the specified number of times
// and returns the average round‑trip latency in milliseconds.
// It returns an error if the host is unreachable or no latency data could be parsed.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("invalid count: %d", count)
	}

	// Build the ping command arguments based on the OS.
	var args []string
	if runtime.GOOS == "windows" {
		args = []string{"-n", strconv.Itoa(count), host}
	} else {
		// Unix‑like systems use -c.
		args = []string{"-c", strconv.Itoa(count), host}
	}

	cmd := exec.Command("ping", args...)
	out, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	// Regular expression to match the latency part.
	// Example formats: "time=2.3 ms", "time=2ms", "time<1ms".
	// We capture the numeric part before "ms".
	re := regexp.MustCompile(`time[=<]?(\d+(?:\.\d+)?)\s*ms`)
	var total float64
	var hits int

	scanner := bufio.NewScanner(strings.NewReader(string(out)))
	for scanner.Scan() {
		line := scanner.Text()
		match := re.FindStringSubmatch(line)
		if match == nil {
			continue
		}
		// match[1] contains the numeric string.
		val, err := strconv.ParseFloat(match[1], 64)
		if err != nil {
			// If we can't parse, skip this line.
			continue
		}
		total += val
		hits++
	}

	if err := scanner.Err(); err != nil {
		return 0, fmt.Errorf("error scanning ping output: %w", err)
	}

	if hits == 0 {
		return 0, fmt.Errorf("no latency data found in ping output")
	}

	avg := total / float64(hits)
	return avg, nil
}

func main() {
	host := "google.com"
	count := 4

	// Simple demo: allow overriding via command line arguments.
	if len(os.Args) > 1 {
		host = os.Args[1]
	}
	if len(os.Args) > 2 {
		n, err := strconv.Atoi(os.Args[2])
		if err != nil {
			fmt.Fprintf(os.Stderr, "invalid count argument: %v\n", err)
			os.Exit(1)
		}
		count = n
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to measure latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avg)
}

