// MeasureLatency pings the specified host a given number of times
// and returns the average latency in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}

	// Determine the ping command arguments based on the operating system
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Unix-like systems (Linux, macOS, etc.)
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.Output()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %v", err)
	}

	outputStr := string(output)

	// Try to parse the statistics line which contains the average
	// Linux format: "rtt min/avg/max/mdev = X.XXX/X.XXX/X.XXX/X.XXX ms"
	// macOS format: "round-trip min/avg/max = X.XXX/X.XXX/X.XXX ms"
	// Windows format: "Minimum = Xms, Maximum = Yms, Average = Zms"

	// Pattern for Linux/macOS statistics line
	statsRe := regexp.MustCompile(`(?i)(?:rtt|round-trip).*?[=/]\s*\d+\.?\d*/(\d+\.?\d*)/\d+\.?\d*(?:\s*ms)?`)
	matches := statsRe.FindStringSubmatch(outputStr)
	if len(matches) > 1 {
		if val, err := strconv.ParseFloat(matches[1], 64); err == nil {
			return val, nil
		}
	}

	// Pattern for Windows statistics line
	windowsRe := regexp.MustCompile(`(?i)Average\s*=\s*(\d+)\s*ms`)
	matches = windowsRe.FindStringSubmatch(outputStr)
	if len(matches) > 1 {
		if val, err := strconv.ParseFloat(matches[1], 64); err == nil {
			return val, nil
		}
	}

	// Fallback: parse individual time values from each response line
	// This works with format: "time=X.XX ms" or "time<X.XX ms"
	timeRe := regexp.MustCompile(`(?i)time[=<](\d+\.?\d*)\s*ms`)
	timeMatches := timeRe.FindAllStringSubmatch(outputStr, -1)

	var total float64
	var timesFound int

	for _, match := range timeMatches {
		if len(match) > 1 {
			if val, err := strconv.ParseFloat(match[1], 64); err == nil {
				total += val
				timesFound++
			}
		}
	}

	if timesFound == 0 {
		return 0, fmt.Errorf("could not parse latency from ping output: %s", truncate(outputStr, 200))
	}

	return total / float64(timesFound), nil
}

// truncate truncates a string to a maximum length
func truncate(s string, maxLen int) string {
