package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average round‑trip time in milliseconds. It uses the system 'ping' command
// via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute the ping command.
	// The -c flag is supported on Linux and macOS.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Locate the line that contains the RTT statistics.
	var statsLine string
	for _, line := range strings.Split(string(output), "\n") {
		// Look for a line that mentions min/avg and contains '=' and 'ms'.
		if strings.Contains(line, "min/avg") && strings.Contains(line, "=") && strings.Contains(line, "ms") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract the part after the '=' sign.
	parts := strings.SplitN(statsLine, "=", 2)
	if len(parts) < 2 {
		return 0, errors.New("invalid RTT statistics line")
	}

	// The first token after '=' holds the slash‑separated latency values.
	// Example: "12.345/23.456/34.567/5.678 ms" or "12.345/23.456/34.567 ms"
	tokens := strings.Fields(parts[1])
	if len(tokens) < 1 {
		return 0, errors.New("missing latency values in RTT statistics")
	}

	values := strings.Split(tokens[0], "/")
	if len(values) < 2 {
		return 0, fmt.Errorf("expected at least min/avg values, got: %s", tokens[0])
	}

	// The second value is the average RTT.
	avg, err := strconv.ParseFloat(values[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency: %w", err)
	}

	return avg, nil
}

// Example usage (optional).
func main() {
	avg, err := MeasureLatency("8.8.8.8", 4)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency: %.2f ms\n", avg)
}

