package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the given host `count` times and returns the average
// round‑trip time in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Limit the number of pings to prevent resource exhaustion.
	const maxCount = 1000
	if count > maxCount {
		count = maxCount
	}

	// Execute ping directly without a shell to avoid command injection.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Locate the line that contains the RTT statistics.
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract the average value. The regex supports both:
	//   rtt min/avg/max/mdev = x/y/z/w ms
	//   rtt min/avg/max = x/y/z ms
	re := regexp.MustCompile(`rtt min/avg/max(?:/mdev)? = ([\d.]+)/([\d.]+)/([\d.]+)`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 3 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[2] // second captured group is the average
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage: ping google.com 4 times.
	host := "google.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency to %s: %.2f ms\n", host, avg)
}

