package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
	"time"
)

// MeasureLatency pings the given host for `count` times and returns the average
// round‑trip latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host is empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be greater than zero")
	}

	// Choose the appropriate flag for the number of probes based on the OS.
	var args []string
	switch runtime.GOOS {
	case "windows":
		args = []string{"-n", strconv.Itoa(count), host}
	case "plan9":
		// Plan 9 uses the same flags as Unix for simplicity.
		args = []string{"-c", strconv.Itoa(count), host}
	default:
		// Linux, macOS, BSD, etc.
		args = []string{"-c", strconv.Itoa(count), host}
	}

	cmd := exec.Command("ping", args...)

	// Set a deadline to avoid hanging indefinitely.
	// Allow roughly 2 seconds per ping plus a small margin.
	timeout := time.Duration(count)*2 + 5
	timer := time.AfterFunc(timeout*time.Second, func() {
		if p := cmd.Process; p != nil {
			p.Kill()
		}
	})
	defer timer.Stop()

	out, err := cmd.Output()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	// The output format varies between operating systems.
	// Try to extract the average latency (in ms) from the output.
	output := string(out)
	var avgStr string

	// Windows: "Average = XXms"
	if idx := strings.Index(output, "Average ="); idx != -1 {
		rest := output[idx+len("Average ="):]
		if i := strings.Index(rest, "ms"); i != -1 {
			avgStr = strings.TrimSpace(rest[:i])
		}
	}

	// Linux / macOS / BSD: look for "=" followed by something like
	// "min/avg/max" or "min/avg/max/mdev".
	if avgStr == "" {
		if idx := strings.Index(output, "="); idx != -1 {
			rest := strings.TrimSpace(output[idx+1:])
			fields := strings.Fields(rest)
			if len(fields) > 0 {
				token := fields[0] // e.g., "0.020/0.030/0.040/0.005"
				if strings.Contains(token, "/") {
					parts := strings.Split(token, "/")
					// For Linux: min/avg/max/mdev → avg is the second part.
					// For macOS: min/avg/max → avg is the second part.
					if len(parts) >= 2 {
						avgStr = parts[1]
					}
				} else {
					// Single value (e.g., "0.030")
					avgStr = token
				}
				// Remove any trailing "ms".
				avgStr = strings.TrimSuffix(avgStr, "ms")
				avgStr = strings.TrimSpace(avgStr)
			}
		}
	}

	if avgStr == "" {
		return 0, errors.New("failed to parse ping output for average latency")
	}

	avgLatency, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	// Ping on most OSes reports milliseconds, but if the value is smaller than
	// 1 ms it could be reported in seconds (rare). Convert in that case.
	if avgLatency < 1.0 {
		avgLatency *= 1000
	}

	return avgLatency, nil
}

func main() {
	// Example: measure latency to a well‑known host.
	host := "example.com"
	count := 4

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, latency)
}

