import (
	"errors"
	"flag"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the given host for `count` times and returns the average
// round‑trip latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("count must be greater than zero")
	}

	// Choose the appropriate flag for the target OS.
	var args []string
	if runtime.GOOS == "windows" {
		args = []string{"-n", strconv.Itoa(count), host}
	} else {
		// Default to Unix‑style ping (Linux, macOS, BSD, etc.)
		args = []string{"-c", strconv.Itoa(count), host}
	}

	cmd := exec.Command("ping", args...)
	out, err := cmd.Output()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	// Regular expression to capture the numeric latency value.
	// Matches patterns like "time=1.23 ms" or "time<1 ms".
	timeRe := regexp.MustCompile(`time[=<](\d+(?:\.\d+)?)`)

	lines := strings.Split(string(out), "\n")
	var sum float64
	var hits int

	for _, line := range lines {
		match := timeRe.FindStringSubmatch(line)
		if len(match) > 1 {
			val, err := strconv.ParseFloat(match[1], 64)
			if err != nil {
				// Skip malformed numbers.
				continue
			}
			sum += val
			hits++
		}
	}

	if hits == 0 {
		return 0, errors.New("no latency values could be parsed from ping output")
	}

	return sum / float64(hits), nil
}

func main() {
	host := flag.String("host", "google.com", "Host to ping")
	count := flag.Int("count", 4, "Number of ping attempts")
	flag.Parse()

	avg, err := MeasureLatency(*host, *count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency to %s: %.2f ms\n", *host, avg)
}

