package main

import (
	"errors"
	"flag"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the given host the specified number of times and returns
// the average latency in milliseconds. It uses the system 'ping' command via
// os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Run ping with -c (or -n on Windows). Here we assume a Unix‑like OS.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping failed for host %q (count %d): %w\nOutput: %s",
			host, count, err, string(output))
	}

	avg, err := parseAvgLatency(string(output))
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency for host %q: %w",
			host, err)
	}
	return avg, nil
}

// parseAvgLatency extracts the average RTT from the ping output.
// It looks for a line that contains "min/avg/max" and then captures the second
// number in the "min/avg/max" group.
func parseAvgLatency(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	// Regex that matches three dot‑separated numbers separated by slashes,
	// e.g. 0.029/0.035/0.040. The second capture group is the average.
	re := regexp.MustCompile(`(\d+\.\d+)/(\d+\.\d+)/(\d+\.\d+)`)

	for _, line := range lines {
		if strings.Contains(line, "min/avg/max") {
			matches := re.FindStringSubmatch(line)
			if len(matches) >= 3 {
				avg, err := strconv.ParseFloat(matches[2], 64)
				if err != nil {
					continue
				}
				return avg, nil
			}
		}
	}
	return 0, errors.New("average latency not found in ping output")
}

func main() {
	host := flag.String("host", "google.com", "Host to ping")
	count := flag.Int("count", 4, "Number of ping attempts")
	flag.Parse()

	avg, err := MeasureLatency(*host, *count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency to %s: %.2f ms\n", *host, avg)
}

