package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds. It uses the system 'ping' command via
// os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Use exec.Command with separate arguments to avoid shell injection
	// vulnerabilities. The host argument is passed directly to the ping
	// binary, not through a shell.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Find the line that contains the average RTT. On Linux it typically looks like:
	//   rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// On macOS it may look like:
	//   round-trip min/avg/max = 12.345/23.456/34.567 ms
	// In both cases the line contains "avg". We match three slash‑separated
	// floating point numbers; the second one is the average.
	outputStr := string(output)
	for _, line := range strings.Split(outputStr, "\n") {
		if !strings.Contains(line, "avg") {
			continue
		}
		re := regexp.MustCompile(`(\d+\.\d+)/(\d+\.\d+)/(\d+\.\d+)`)
		matches := re.FindStringSubmatch(line)
		if len(matches) < 3 {
			continue
		}
		avg, err := strconv.ParseFloat(matches[2], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency: %w", err)
		}
		return avg, nil
	}

	return 0, errors.New("could not find average latency in ping output")
}

func main() {
	// Example usage: ping "google.com" 4 times.
	avg, err := MeasureLatency("google.com", 4)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency to google.com: %.2f ms\n", avg)
}

