package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
	"time"
)

// MeasureLatency measures the latency to a host by pinging it specified number of times
// and returns the average latency in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	if host == "" {
		return 0, errors.New("host cannot be empty")
	}

	// Determine the ping flag based on OS
	// Windows uses -n, Unix-like systems use -c
	pingFlag := "-c"
	if isWindows() {
		pingFlag = "-n"
	}

	// Execute ping command with timeout
	output, err := exec.Command("ping", pingFlag, strconv.Itoa(count), host).Output()
	if err != nil {
		// Try to get more detailed error message
		cmd := exec.Command("ping", pingFlag, strconv.Itoa(count), host)
		errOutput, _ := cmd.CombinedOutput()
		return 0, fmt.Errorf("ping failed: %w, output: %s", err, string(errOutput))
	}

	// Parse the output to extract latency values
	lines := strings.Split(string(output), "\n")
	var latencies []float64

	for _, line := range lines {
		// Look for lines containing "time=" which indicate successful ping responses
		// Format: "64 bytes from 93.184.216.34: icmp_seq=0 ttl=51 time=23.4 ms"
		if strings.Contains(line, "time=") {
			// Extract the time value from the line
			idx := strings.Index(line, "time=")
			if idx == -1 {
				continue
			}

			timeStr := line[idx+5:] // Skip "time="
			// Find the " ms" to extract just the number
			if endIdx := strings.Index(timeStr, " ms"); endIdx != -1 {
				timeStr = timeStr[:endIdx]
			}

			latency, err := strconv.ParseFloat(strings.TrimSpace(timeStr), 64)
			if err != nil {
				continue // Skip lines where parsing fails
			}

			latencies = append(latencies, latency)
		}
	}

	if len(latencies) == 0 {
		return 0, errors.New("no latency data found in ping output")
	}

	// Calculate average latency
	var total float64
	for _, lat := range latencies {
		total += lat
	}

	avgLatency := total / float64(len(latencies))
	return avgLatency, nil
}

// isWindows checks if the current operating system is Windows
func isWindows() bool {
	return strings.Contains(strings.ToLower(runtime.GOOS), "windows")
}

func main() {
	// Example usage - can be modified as needed
	host := "google.com"
	count := 4

	// Allow overriding via command line arguments
	if len(os.Args) > 1 {
		host = os.Args[1]
	}
	if len(os.Args) > 2 {
		c, err := strconv.Atoi(os.Args[2])
		if err == nil {
			count = c
		}
	}

	fmt.Printf("Pinging %s with %d attempts...\n", host, count)

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, latency)
}

