package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the given host `count` times and returns the average
// round‑trip time in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host is empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be greater than zero")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		// Windows uses -n to specify the number of packets.
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		// Linux/macOS use -c.
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	out, err := cmd.Output()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w", err)
	}

	// Example ping output on Linux:
	//   64 bytes from 142.250.185.206: icmp_seq=1 ttl=115 time=11.2 ms
	// On Windows:
	//   Reply from 142.250.185.206: bytes=32 time=11ms TTL=115
	// Extract the numeric latency value (the part after "time=" or "time").
	re := regexp.MustCompile(`time[=<](\d+(?:\.\d+)?)\s*ms?`)
	matches := re.FindAllStringSubmatch(string(out), -1)

	var total float64
	var found int
	for _, m := range matches {
		if len(m) < 2 {
			continue
		}
		val, err := strconv.ParseFloat(m[1], 64)
		if err != nil {
			continue
		}
		total += val
		found++
	}

	if found == 0 {
		return 0, errors.New("could not parse latency from ping output")
	}

	return total / float64(found), nil
}

func main() {
	host := "google.com"
	count := 5

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency to %s: %.2f ms\n", host, avg)
}

