package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be a positive integer")
	}

	// Use separate arguments to avoid shell quoting issues.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)

	// Locate the line that contains the RTT statistics.
	var statsLine string
	for _, line := range lines(outputStr) {
		// Look for either Linux "rtt min/avg/max/mdev" or macOS "round-trip min/avg/max".
		if strings.Contains(line, "rtt min/avg/max") || strings.Contains(line, "round-trip min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// The format after the equal sign is:
	//   <min>/<avg>/<max>[/<mdev>] [ms]
	// Example (Linux): rtt min/avg/max/mdev = 1.234/2.345/3.456/0.789 ms
	// Example (macOS): round-trip min/avg/max = 1.234/2.345/3.456 ms
	parts := strings.Split(statsLine, "=")
	if len(parts) < 2 {
		return 0, errors.New("unable to parse RTT statistics")
	}

	// Split the right‑hand side by '/' to obtain the average.
	times := strings.Split(strings.TrimSpace(parts[1]), "/")
	if len(times) < 2 {
		return 0, errors.New("unable to parse average latency")
	}

	// Remove possible trailing "ms" unit.
	avgStr := strings.TrimSpace(times[1])
	avgStr = strings.TrimSuffix(avgStr, "ms")
	avgStr = strings.TrimSpace(avgStr)

	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

// lines returns a slice of lines from the input string, trimming the trailing newline.
func lines(s string) []string {
	return strings.Split(strings.TrimSuffix(s, "\n"), "\n")
}

func main() {
	// Example usage: ping google.com 4 times.
	host := "google.com"
	count := 4

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

