package main

import (
	"fmt"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}

	// Determine the flag for number of packets based on OS
	flag := "-c"
	if runtime.GOOS == "windows" {
		flag = "-n"
	}

	cmd := exec.Command("ping", flag, strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w", err)
	}

	// Parse the output to extract latency values
	// Example line: "64 bytes from 8.8.8.8: icmp_seq=1 ttl=118 time=14.5 ms"
	lines := strings.Split(string(output), "\n")
	var totalLatency float64
	var latenciesFound int

	for _, line := range lines {
		if strings.Contains(line, "time=") {
			// Extract the time value
			idx := strings.Index(line, "time=")
			if idx == -1 {
				continue
			}
			// Get the substring after "time="
			timeStr := line[idx+5:] // len("time=") is 5
			// Trim spaces and "ms"
			timeStr = strings.TrimSpace(timeStr)
			timeStr = strings.TrimSuffix(timeStr, " ms")
			timeStr = strings.TrimSuffix(timeStr, "ms")

			latency, err := strconv.ParseFloat(timeStr, 64)
			if err != nil {
				continue // Skip malformed lines
			}
			totalLatency += latency
			latenciesFound++
		}
	}

	if latenciesFound == 0 {
		return 0, fmt.Errorf("no latency data found in ping output")
	}

	averageLatency := totalLatency / float64(latenciesFound)
	return averageLatency, nil
}

func main() {
	// Example usage
	host := "8.8.8.8"
	count := 4

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, latency)
}

