// MeasureLatency pings the given host a specified number of times and returns
// the average round‑trip latency in milliseconds. The underlying ping command
// is chosen based on the OS (Linux/macOS uses "-c", Windows uses "-n").
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host is empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be greater than zero")
	}

	// Build ping command arguments according to the platform.
	var args []string
	if runtime.GOOS == "windows" {
		args = []string{"-n", strconv.Itoa(count), host}
	} else {
		// Default to Unix-style ping (Linux, macOS, etc.)
		args = []string{"-c", strconv.Itoa(count), host}
	}

	cmd := exec.Command("ping", args...)
	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	err := cmd.Run()
	if err != nil {
		// Return error if ping fails (e.g., host unreachable).
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	output := stdout.String()
	if stderr.Len() > 0 {
		output += "\n" + stderr.String()
	}

	// Regex to capture latency values. Matches strings like:
	//   time=1.23 ms
	//   time=45ms
	//   time=0.123ms
	re := regexp.MustCompile(`time[=<]?(\d+(?:\.\d+)?)\s*ms`)
	matches := re.FindAllStringSubmatch(output, -1)

	if len(matches) == 0 {
		return 0, errors.New("no latency values found in ping output")
	}

	var total float64
	for _, m := range matches {
		if len(m) < 2 {
			continue
		}
		val, err := strconv.ParseFloat(m[1], 64)
		if err != nil {
			// Skip malformed numbers.
			continue
		}
		total += val
	}

	avg := total / float64(len(matches))
	return avg, nil
}

func main() {
