package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute ping directly without a shell to avoid quoting issues.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Locate the line that contains the RTT statistics.
	outputStr := string(output)
	var statsLine string
	for _, line := range strings.Split(outputStr, "\n") {
		if strings.Contains(line, "rtt min/avg/max") || strings.Contains(line, "min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// The line looks like:
	//   rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	//   (or without mdev:  rtt min/avg/max = 12.345/23.456/34.567 ms)
	// Split on "=" and take the right‑hand side.
	parts := strings.SplitN(statsLine, "=", 2)
	if len(parts) != 2 {
		return 0, errors.New("invalid RTT statistics format")
	}
	right := strings.TrimSpace(parts[1])
	// Remove trailing "ms" if present.
	right = strings.TrimRight(right, "ms")
	right = strings.TrimSpace(right)

	// The remaining string is like "12.345/23.456/34.567/5.678"
	// Split on "/" – the second element (index 1) is the average.
	nums := strings.Split(right, "/")
	if len(nums) < 2 {
		return 0, errors.New("invalid RTT statistics format")
	}
	avgStr := nums[1]

	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency: %w", err)
	}
	return avg, nil
}

func main() {
	// Simple demo: accept host and optional count from command line.
	host := "google.com"
	count := 4

	if len(os.Args) > 1 {
		host = os.Args[1]
	}
	if len(os.Args) > 2 {
		if c, err := strconv.Atoi(os.Args[2]); err == nil {
			count = c
		}
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency to %s: %.2f ms\n", host, avg)
}

