package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds. It uses the system 'ping' command via
// os/exec and parses the output to extract the average round‑trip time.
func MeasureLatency(host string, count int) (float64, error) {
	// Basic input validation
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	// Reject hosts that start with '-' to avoid being interpreted as a flag
	if strings.HasPrefix(host, "-") {
		return 0, errors.New("host must not start with a dash")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}
	// Optional sanity limit to avoid abuse
	const maxCount = 1024
	if count > maxCount {
		return 0, fmt.Errorf("count exceeds maximum allowed value (%d)", maxCount)
	}

	// Use exec.Command directly; this avoids shell injection vulnerabilities.
	// On Linux the flag -c specifies the number of packets.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	// Locate the line that contains the RTT statistics. Typical formats:
	//   rtt min/avg/max/mdev = X/Y/Z/W ms
	//   round-trip min/avg/max = X/Y/Z ms
	outputStr := string(output)
	var statsLine string
	for _, line := range strings.Split(outputStr, "\n") {
		if strings.Contains(line, "=") && strings.Contains(line, "ms") {
			statsLine = line
			break
		}
	}
	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract the average latency. The regular expression captures the second
	// number (the average) from the "X/Y/Z" or "X/Y/Z/W" part.
	// It matches both "rtt min/avg/max" and "round-trip min/avg/max", and
	// optionally the "/mdev" portion.
	re := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max(?:/mdev)?\s*=\s*[\d.]+/([\d.]+)/[\d.]+(?:/[\d.]+)?\s*ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

// Simple demonstration of MeasureLatency.
func main() {
	// You can change host and count to suit your needs.
	host := "example.com"
	count := 4

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency to %s: %.2f ms\n", host, latency)
}

