package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"time"
)

// MeasureLatency pings the given host `count` times and returns the average
// latency in milliseconds. It uses the OS ping command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("count must be greater than zero")
	}

	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	out, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	// Regex to extract time in milliseconds from ping output.
	// Matches patterns like: time=2.3 ms, time<2ms, time=2ms
	re := regexp.MustCompile(`time[=<]?(\d+(?:\.\d+)?)\s*ms`)
	matches := re.FindAllStringSubmatch(string(out), -1)

	if len(matches) == 0 {
		return 0, errors.New("no latency information found in ping output")
	}

	var sum float64
	for _, m := range matches {
		// m[1] holds the numeric portion (e.g., "2.3")
		val, err := strconv.ParseFloat(m[1], 64)
		if err != nil {
			continue // skip invalid numbers
		}
		sum += val
	}

	average := sum / float64(len(matches))
	return average, nil
}

func main() {
	// Simple CLI: usage: latency [host] [count]
	host := "example.com"
	count := 4

	if len(os.Args) > 1 {
		host = os.Args[1]
	}
	if len(os.Args) > 2 {
		if c, err := strconv.Atoi(os.Args[2]); err == nil {
			count = c
		}
	}

	start := time.Now()
	avg, err := MeasureLatency(host, count)
	elapsed := time.Since(start)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s (%d pings): %.2f ms (measurement took %v)\n",
		host, count, avg, elapsed)
}

