package main

import (
	"bufio"
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the given host the specified number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host is empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be greater than zero")
	}

	// Determine platform-specific ping arguments.
	var args []string
	switch runtime.GOOS {
	case "windows":
		// Windows uses -n to specify the number of packets.
		args = []string{"-n", strconv.Itoa(count), host}
	case "linux", "darwin", "freebsd", "openbsd", "netbsd":
		// Unix-like systems use -c.
		args = []string{"-c", strconv.Itoa(count), host}
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	// Execute the ping command.
	cmd := exec.Command("ping", args...)
	stdout, err := cmd.StdoutPipe()
	if err != nil {
		return 0, fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	if err := cmd.Start(); err != nil {
		return 0, fmt.Errorf("failed to start ping: %w", err)
	}

	// Scan the output line by line.
	scanner := bufio.NewScanner(stdout)
	var totalLatency float64
	var replyCount int

	// Regex to match latency in the ping output.
	// Matches patterns like "time=12.3 ms" or "time=12 ms".
	latencyRe := regexp.MustCompile(`time=(\d+(?:\.\d+)?)\s*ms`)

	for scanner.Scan() {
		line := scanner.Text()
		matches := latencyRe.FindStringSubmatch(line)
		if len(matches) == 2 {
			latency, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				// Ignore parse errors for malformed numbers.
				continue
			}
			totalLatency += latency
			replyCount++
		}
	}

	if err := scanner.Err(); err != nil {
		return 0, fmt.Errorf("error scanning ping output: %w", err)
	}

	// Wait for the command to finish.
	if err := cmd.Wait(); err != nil {
		// If the process exited with an error, we still may have collected replies.
		// If no replies were collected, treat it as an error.
		if replyCount == 0 {
			return 0, fmt.Errorf("ping command failed: %w", err)
		}
	}

	if replyCount == 0 {
		return 0, errors.New("no ping replies received")
	}

	averageLatency := totalLatency / float64(replyCount)
	return averageLatency, nil
}

func main() {
	// Example: ping "example.com" 4 times.
	host := "example.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency to %s (ping %d times): %.2f ms\n", host, count, avg)
}

