package main

import (
	"errors"
	"flag"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"strconv"
)

// MeasureLatency pings the given host for the specified number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Run the ping command.
	// -c is the standard flag for the number of packets on Unix.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping failed: %w", err)
	}

	// Extract all occurrences of "time=XX.XX" from the output.
	re := regexp.MustCompile(`time=([0-9]+\.?[0-9]*)`)
	matches := re.FindAllStringSubmatch(string(output), -1)
	if len(matches) == 0 {
		return 0, errors.New("could not parse latency from ping output")
	}

	var total float64
	for _, match := range matches {
		if len(match) < 2 {
			continue
		}
		val, err := strconv.ParseFloat(match[1], 64)
		if err != nil {
			continue
		}
		total += val
	}

	avg := total / float64(len(matches))
	return avg, nil
}

func main() {
	// Simple command‑line interface using the flag package.
	// Defaults: host = "google.com", count = 4.
	hostPtr := flag.String("host", "google.com", "Host to ping")
	countPtr := flag.Int("count", 4, "Number of ping attempts")
	flag.Parse()

	avg, err := MeasureLatency(*hostPtr, *countPtr)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency to %s: %.2f ms\n", *hostPtr, avg)
}

