// MeasureLatency pings the given host the specified number of times
// and returns the average round‑trip latency in milliseconds.
// It uses the native ping command for the current operating system.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, fmt.Errorf("host is empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be a positive integer")
	}

	// Build the ping command arguments based on the OS
	var args []string
	if runtime.GOOS == "windows" {
		args = []string{"-n", strconv.Itoa(count), host}
	} else {
		// Linux, macOS, etc.
		// -c: number of pings
		// -W: timeout in seconds for each ping
		args = []string{"-c", strconv.Itoa(count), "-W", "2", host}
	}

	cmd := exec.Command("ping", args...)
	output, err := cmd.Output()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	// Regex to capture "time=XX ms" (or "time=XXms")
	re := regexp.MustCompile(`time=(\d+\.?\d*)\s*ms`)

	var total float64
	var found int

	// Iterate over each line of the ping output
	for _, line := range strings.Split(string(output), "\n") {
		matches := re.FindStringSubmatch(line)
		if len(matches) > 1 {
			val, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				// If parsing fails for a line, skip it
				continue
			}
			total += val
			found++
		}
	}

	if found == 0 {
		return 0, fmt.Errorf("no latency data found in ping output")
	}

	average := total / float64(found)
	return average, nil
}

func main() {
	host := "google.com"
	count := 4 // default number of pings

	// Allow optional command‑line arguments
	if len(os.Args) > 1 {
		host = os.Args[1]
	}
	if len(os.Args) > 2 {
		c, err := strconv.Atoi(os.Args[2])
		if err != nil {
			fmt.Fprintf(os.Stderr, "Invalid count value: %v\n", err)
			os.Exit(1)
		}
		count = c
	}

