package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the given host `count` times and returns the average
// round‑trip latency in milliseconds. It uses the system `ping` command via
// os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be a positive integer")
	}

	// Execute "ping -c <count> <host>" directly. Using exec.Command avoids
	// the need for shell quoting and makes the call portable.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping failed: %w; output: %s", err, string(output))
	}

	// Look for the line that contains the RTT statistics. The exact wording
	// differs between Linux ("rtt min/avg/max/mdev = ...") and macOS
	// ("round-trip min/avg/max = ..."), but any line that contains '=' and
	// "ms" will hold the numbers we need.
	var statsLine string
	for _, line := range strings.Split(string(output), "\n") {
		if strings.Contains(line, "=") && strings.Contains(line, "ms") {
			statsLine = line
			break
		}
	}
	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// The average is the second slash‑separated number in the statistics line.
	// The regex matches three (or four) numbers separated by '/'; we capture the
	// second one (average). It also accepts integers without a decimal part.
	re := regexp.MustCompile(`(\d+(?:\.\d+)?)/(\d+(?:\.\d+)?)/(\d+(?:\.\d+)?)`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 3 {
		return 0, fmt.Errorf("failed to parse latency from line: %s", statsLine)
	}

	avg, err := strconv.ParseFloat(matches[2], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage: ping google.com 4 times.
	avg, err := MeasureLatency("google.com", 4)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency: %.2f ms\n", avg)
}

