func MeasureLatency(host string, count int) (float64, error) {
	// Validate input
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count <= 0 {
		return 0, fmt.Errorf("count must be positive")
	}

	// Execute the ping command
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w", err)
	}

	// Parse the output to extract latencies
	// Regular expression to match time in milliseconds (e.g., "time=12.3 ms" or "time=12.3ms")
	re := regexp.MustCompile(`time=(\d+\.?\d*)\s*ms`)
	var latencies []float64

	scanner := bufio.NewScanner(strings.NewReader(string(output)))
	for scanner.Scan() {
