			if err != nil {
				return 0, fmt.Errorf("failed to parse latency: %w", err)
			}
			latencies = append(latencies, latency)
		}
	}

	if err := scanner.Err(); err != nil {
		return 0, fmt.Errorf("error reading ping output: %w", err)
	}

	// Check if we got any latencies
	if len(latencies) == 0 {
		return 0, fmt.Errorf("no latency data received from ping")
	}

	// Calculate average latency
	var total float64
	for _, lat := range latencies {
		total += lat
	}
	average := total / float64(len(latencies))

	return average, nil
}

