)

// MeasureLatency pings the given host for the specified number of packets
// and returns the average round‑trip time in milliseconds. It uses the
// system "ping" command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("count must be greater than 0")
	}
	if strings.TrimSpace(host) == "" {
		return 0, errors.New("host is empty")
	}

	// Run "ping -c <count> <host>" (Linux). On Windows use "-n".
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	var out bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &out // Merge stderr into stdout for easier parsing.

	if err := cmd.Run(); err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	output := out.String()

	// Try to extract the average from the final line that looks like:
	// rtt min/avg/max/mdev = <min>/<avg>/<max>/<mdev> ms
	re := regexp.MustCompile(`rtt min/avg/max/mdev = ([\d.]+)/([\d.]+)/([\d.]+)/([\d.]+)`)
	match := re.FindStringSubmatch(output)
	if len(match) >= 3 {
		avg, err := strconv.ParseFloat(match[2], 64)
		if err == nil {
			return avg, nil
		}
	}

	// Fallback: parse individual "time=XX ms" lines (useful on macOS,
	// Windows, or when the final line is missing).
	reTime := regexp.MustCompile(`time[=<]?([\d.]+)\s*ms`)
	times := reTime.FindAllStringSubmatch(output, -1)

	var total float64
	var found int
	for _, t := range times {
		if len(t) > 1 {
			v, err := strconv.ParseFloat(t[1], 64)
			if err == nil {
				total += v
				found++
			}
		}
	}

	if found == 0 {
		return 0, errors.New("could not parse latency from ping output")
	}

	return total / float64(found), nil
}

func main() {
	if len(os.Args) < 2 {
		fmt.Fprintln(os.Stderr, "Usage: go run main.go <host> [count]")
		os.Exit(1)
	}

	host := os.Args[1]
	count := 4 // default number of pings
	if len(os.Args) >= 3 {
		c, err := strconv.Atoi(os.Args[2])
		if err != nil {
			fmt.Fprintf(os.Stderr, "Invalid count %q: %v\n", os.Args[2], err)
			os.Exit(1)
		}
		count = c
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avg)
}

