// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Choose the flag for the number of ping packets based on the operating system.
	countFlag := "-c"
	if runtime.GOOS == "windows" {
		countFlag = "-n"
	}

	// Execute ping directly without a shell, avoiding quoting issues.
	cmd := exec.Command("ping", countFlag, strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)

	// Find the line that contains the round‑trip time statistics.
	var statsLine string
	for _, line := range strings.Split(outputStr, "\n") {
		if strings.Contains(line, "min/avg") || strings.Contains(line, "round-trip") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// The statistics line may look like:
	//   rtt min/avg/max/mdev = 1.234/2.345/3.456/0.123 ms
	//   round-trip min/avg/max = 1.234/2.345/3.456 ms
	// Capture the average (the second number after the first '/').

	// Primary pattern: works with both "rtt" and "round-trip" and optional mdev.
	re := regexp.MustCompile(`(?i)(?:rtt|round-trip).*=.*?(\d+\.\d+)/(\d+\.\d+)`)
	matches := re.FindStringSubmatch(statsLine)

	if len(matches) >= 3 {
		avg, err := strconv.ParseFloat(matches[2], 64)
		if err == nil {
			return avg, nil
		}
	}

	// Fallback pattern: just look for the part after '=' containing numbers separated by '/'.
	re2 := regexp.MustCompile(`= (\d+\.\d+)/(\d+\.\d+)`)
	matches = re2.FindStringSubmatch(statsLine)
	if len(matches) < 3 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avg, err := strconv.ParseFloat(matches[2], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Simple demonstration: accept host and optional count from command‑line arguments.
	host := "example.com"
	count := 4

	if len(os.Args) > 1 {
		host = os.Args[1]
	}
	if len(os.Args) > 2 {
		c, err := strconv.Atoi(os.Args[2])
		if err == nil && c > 0 {
			count = c
		}
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avg)
}

